                supplier_deliv[day][sup][p] = q
    elif "text-template" in f:
        for line in text.strip().split('\n'):
            if "delivered" in line:
                q = int(re.search(r"delivered\s+(\d+)\s+units", line).group(1))
                p = re.search(r"product\s+(P_\d+)", line).group(1)
                supplier_deliv[day][sup][p] = q

