store_orders = defaultdict(lambda: defaultdict(dict))
for f in glob.glob("/app/raw_orders/day_*.*"):
    day = int(re.search(r"day_(\d+)", f).group(1))
    store = re.search(r"(S_\d+)", f).group(1)

    with open(f, 'r') as file:
